public double solve(final UnivariateRealFunction f, final double min, final double max, final double initial) throws MaxIterationsExceededException, FunctionEvaluationException {
    clearResult();
    if (f == null || min == max || initial < min || initial > max || Double.isNaN(min) || Double.isInfinite(max) || Double.isNaN(initial) || Double.isInfinite(max)) {
        throw new IllegalArgumentException("Invalid input parameters");
    }
    double yMin = f.value(min);
    double yMax = f.value(max);
    double yInitial = f.value(initial);
    if (Math.abs(yInitial) <= functionValueAccuracy) {
        setResult(initial, 0);
        return result;
    }
    if (Math.abs(yMin) <= functionValueAccuracy) {
        setResult(yMin, 0);
        return result;
    }
    if (Math.abs(yMax) <= functionValueAccuracy) {
        setResult(yMax, 0);
        return result;
    }
    if (Math.signum(yInitial) == Math.signum(yMin)) {
        throw new IllegalArgumentException("Initial guess must be between the endpoints");
    }
    if (yInitial * yMin < 0) {
        return solve(f, min, yMin, initial, yInitial, min, yMin);
    }
    if (yInitial * yMax < 0) {
        return solve(f, initial, yInitial, max, yMax, initial, yInitial);
    }
    return solve(f, min, yMin, max, yMax, initial, yInitial);
}
